// After (Introduce Foreign Method in client class)
private Date nextWorkday(Date date) {
  Date next = new Date(date.getTime() + 86400000);
  while (next.getDay() == 0 || next.getDay() == 6) {
    next = new Date(next.getTime() + 86400000);
  }
  return next;
}

